UPDATE
    NMCP_VIOLATION_REPORT
SET
    REPORT_STATUS = #{reportStatus}
    ,REPORT_ANSWER = #{reportAnswer}

        ,REPORT_RCV_CPLT_DT = SYSDATE


        ,REPORT_ADMIN_ID = #{reportAdminId}
        ,REPORT_ANSWER_DT = SYSDATE

WHERE
    REPORT_SEQ = #{reportSeq}

mapper.select:
SELECT REPORT_SEQ , REPORT_CERT_NUMBER , REPORT_NAME , REPORT_MOBILE_NO , REPORT_EMAIL , REPORT_TITLE , REPORT_CONTENT , REPORT_FILE_NAME , REPORT_ORG_FILE_NAME , REPORT_RESULT_NOTIC , REPORT_STATUS , REPORT_REG_DT , REPORT_ANSWER_DT , REPORT_ADMIN_ID , REPORT_RCV_CPLT_DT , REPORT_ANSWER , ROW_NUMBER() OVER (ORDER BY REPORT_REG_DT ASC) AS RNUM FROM NMCP_VIOLATION_REPORT A WHERE 1=1
AND REPORT_STATUS = #{reportStatus}
AND REPORT_TITLE LIKE '%'||#{searchText}||'%'
AND REPORT_NAME = #{searchText}
ORDER BY REPORT_REG_DT DESC

SELECT COUNT(*) FROM NMCP_VIOLATION_REPORT WHERE 1=1
AND REPORT_STATUS = #{reportStatus}
AND REPORT_TITLE LIKE '%'||#{searchText}||'%'
AND REPORT_NAME = #{searchText}

SELECT BOARD_SEQ , BOARD_CTG_SEQ , BOARD_SUBJECT , BOARD_WRITER_NM , NOTI_YN , VIEW_YN , BOARD_WRITE_DT , BOARD_ATT_YN , CRET_DT , NEXT_SEQ , NEXT_SUBJECT , NEXT_DT , PRE_SEQ , PRE_SUBJECT , PRE_DT FROM ( SELECT BOARD_SEQ, BOARD_CTG_SEQ, BOARD_SUBJECT, BOARD_WRITER_NM, NOTI_YN, VIEW_YN, TO_CHAR(BOARD_WRITE_DT, 'YYYY.MM.DD') AS BOARD_WRITE_DT, BOARD_ATT_YN, CRET_DT, lead(BOARD_SEQ,1) over (order by BOARD_WRITE_DT, BOARD_SEQ) NEXT_SEQ, lead(BOARD_SUBJECT,1,'다음글이 없습니다.') over (order by BOARD_WRITE_DT, BOARD_SEQ) NEXT_SUBJECT, lead(CRET_DT,1,'') over (order by BOARD_WRITE_DT, BOARD_SEQ) NEXT_DT, lag(BOARD_SEQ,1) over (order by BOARD_WRITE_DT, BOARD_SEQ) PRE_SEQ, lag(BOARD_SUBJECT,1,'이전글이 없습니다.') over (order by BOARD_WRITE_DT, BOARD_SEQ) PRE_SUBJECT, lag(CRET_DT,1,'') over (order by BOARD_WRITE_DT, BOARD_SEQ) PRE_DT FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = 93
AND (UPPER(fnHTMLtoTEXT(BOARD_SUBJECT)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!' OR UPPER(fnHTMLtoTEXT(BOARD_CONTENTS)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!')
AND NOTI_YN = 'N' AND VIEW_YN = 'Y' ) WHERE BOARD_SEQ = #{boardSeq}
